 * ========================================================================= */
describe('loading placeholder', () => {
  /**
   * Hold EVERY fetch open until `release()` is called, then resolve it to a
   * browse result. The loading placeholder is committed synchronously before
   * the await, so inspecting `.results` before `release()`/`flush()` observes
   * the placeholder without depending on the eventual response body.
   */
  function stubHeldFetch(): { release: () => void } {
    let release!: () => void;
